// Transform AI Agent output to Due Diligence HTML template format
const raw = $input.first()?.json ?? {};
const data = raw.output && typeof raw.output === 'object' ? raw.output : raw;

function isMissing(value) {
  return value === null || value === undefined || value === '' || (typeof value === 'string' && value.trim() === '');
}

function escapeHtml(value) {
  return String(value)
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
}

function textValue(value, fallback = 'Not Available') {
  return isMissing(value) ? fallback : String(value);
}

function numberValue(value, fallback = 'Not Available') {
  if (typeof value === 'number') {
    if (!Number.isFinite(value) || value === 0) return fallback;
    return value.toLocaleString('en-US');
  }

  if (typeof value === 'string') {
    const trimmed = value.trim();
    if (!trimmed || trimmed === '0') return fallback;
    return trimmed;
  }

  return fallback;
}

function generateRevenueRows(revenueHistory) {
  if (!Array.isArray(revenueHistory) || revenueHistory.length === 0) {
    return '<tr><td colspan="3" class="na-value">No revenue data available</td></tr>';
  }

  return revenueHistory.map((row) => {
    const year = textValue(row?.year, 'N/A');
    const amount = numberValue(row?.amount);
    const currency = textValue(row?.currency, 'USD');

    return `
    <tr>
      <td>${escapeHtml(year)}</td>
      <td>${escapeHtml(amount)}</td>
      <td>${escapeHtml(currency)}</td>
    </tr>
  `;
  }).join('');
}

function generateRiskItems(risks) {
  const cleanRisks = Array.isArray(risks)
    ? risks.filter((risk) => !isMissing(risk)).map((risk) => String(risk))
    : [];

  if (cleanRisks.length === 0) {
    return '<li class="risk-item"><span class="risk-icon">-</span><span class="risk-text">No specific risks identified in the document</span></li>';
  }

  return cleanRisks.map((risk, index) => `
    <li class="risk-item">
      <span class="risk-icon">${index + 1}</span>
      <span class="risk-text">${escapeHtml(risk)}</span>
    </li>
  `).join('');
}

const companyProfile = data.company_profile || {};
const financials = data.financials || {};
const analysis = data.analysis || {};
const margins = financials.margins || {};

const dealId = $('Prepare Analysis Context').first()?.json?.dealId || 'N/A';
const reportDate = DateTime.now().toFormat("MMMM dd, yyyy 'at' HH:mm");

return [{
  json: {
    companyName: textValue(companyProfile.company_name),
    industry: textValue(companyProfile.industry),
    location: textValue(companyProfile.location),
    employeeCount: numberValue(companyProfile.employee_count),

    revenueTableRows: generateRevenueRows(financials.revenue_history),
    ebitda: numberValue(financials.ebitda),
    grossMargin: textValue(margins.gross_margin),
    netMargin: textValue(margins.net_margin),
    ebitdaMargin: textValue(margins.ebitda_margin),

    businessModel: textValue(analysis.business_model),
    investmentThesis: textValue(analysis.investment_thesis),
    riskListItems: generateRiskItems(analysis.key_risks),
    customerConcentration: textValue(analysis.customer_concentration),

    dealId: textValue(dealId, 'N/A'),
    reportDate,
  },
}];

