const stats = $input.first().json;
  const originalItems = $('Split Uploaded Files + Build Deal ID').all();
  const dealId = originalItems[0]?.json?.dealId;

  // Check if namespace exists
  const namespaceExists = stats.namespaces && stats.namespaces[dealId];
  const vectorCount = namespaceExists ? stats.namespaces[dealId].vectorCount : 0;

  if (vectorCount > 0) {
    // Cache HIT - return single item for analysis path
    return [{
      json: {
        dealId: dealId,
        cacheHit: true,
        vectorCount: vectorCount,
        message: `Cache HIT: ${vectorCount} vectors found`
      }
    }];
